"use client";

import Link from "next/link";
import { useState } from "react";

import { clearToken } from "@/lib/auth";

export default function SettingsPage() {
  const [email, setEmail] = useState("developer@ethereal.sys");
  const [password, setPassword] = useState("");

  return (
    <main className="settings-shell">
      <section className="settings-card">
        <div className="settings-header">
          <h1>Settings</h1>
          <Link href="/chat" className="btn ghost">
            Back to chat
          </Link>
        </div>

        <label className="auth-label">EMAIL</label>
        <input className="field dark" value={email} onChange={(event) => setEmail(event.target.value)} />

        <label className="auth-label">NEW PASSWORD</label>
        <input
          className="field dark"
          type="password"
          value={password}
          placeholder="••••••••"
          onChange={(event) => setPassword(event.target.value)}
        />

        <div className="settings-actions">
          <button className="btn primary" onClick={() => window.alert("Profile settings saved (mock).")}>
            Save changes
          </button>
          <button
            className="btn danger"
            onClick={() => {
              clearToken();
              window.location.href = "/login";
            }}
          >
            Log out
          </button>
        </div>
      </section>
    </main>
  );
}
